"""
Binance Futures Testnet Connector
"""
import hmac
import hashlib
import time
import json
import requests
from urllib.parse import urlencode
from datetime import datetime


class BinanceTestnet:
    def __init__(self, api_key, api_secret, base_url):
        self.api_key = api_key
        self.api_secret = api_secret
        self.base_url = base_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'X-MBX-APIKEY': self.api_key})

    def _sign(self, params):
        query = urlencode(params)
        sig = hmac.new(self.api_secret.encode(), query.encode(), hashlib.sha256).hexdigest()
        params['signature'] = sig
        return params

    def _ts(self):
        return int(time.time() * 1000)

    def _get(self, path, params=None, signed=False):
        if params is None:
            params = {}
        if signed:
            params['timestamp'] = self._ts()
            params = self._sign(params)
        try:
            r = self.session.get(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            else:
                return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    def _post(self, path, params=None):
        if params is None:
            params = {}
        params['timestamp'] = self._ts()
        params = self._sign(params)
        try:
            r = self.session.post(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            else:
                return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    def _delete(self, path, params=None):
        if params is None:
            params = {}
        params['timestamp'] = self._ts()
        params = self._sign(params)
        try:
            r = self.session.delete(f"{self.base_url}{path}", params=params, timeout=30)
            if r.status_code == 200:
                return r.json()
            else:
                return {'error': r.status_code, 'msg': r.text[:200]}
        except Exception as e:
            return {'error': str(e)}

    # ========== PUBLIC ==========
    def get_price(self, symbol):
        data = self._get('/fapi/v1/ticker/price', {'symbol': symbol})
        if 'error' not in data:
            return float(data['price'])
        return None

    def get_candles(self, symbol, interval='15m', limit=100):
        data = self._get('/fapi/v1/klines', {
            'symbol': symbol, 'interval': interval, 'limit': limit
        })
        if isinstance(data, list):
            candles = []
            for c in data:
                candles.append({
                    'time': c[0],
                    'open': float(c[1]),
                    'high': float(c[2]),
                    'low': float(c[3]),
                    'close': float(c[4]),
                    'volume': float(c[5]),
                    'quote_vol': float(c[7]),
                    'trades': int(c[8]),
                    'taker_buy_vol': float(c[9]),
                    'taker_buy_quote': float(c[10]),
                })
            return candles
        return []

    def get_agg_trades(self, symbol, limit=500):
        data = self._get('/fapi/v1/aggTrades', {
            'symbol': symbol, 'limit': limit
        })
        if isinstance(data, list):
            trades = []
            for t in data:
                trades.append({
                    'price': float(t['p']),
                    'qty': float(t['q']),
                    'time': t['T'],
                    'is_buyer_maker': t['m'],  # True = seller initiated
                })
            return trades
        return []

    def get_depth(self, symbol, limit=20):
        data = self._get('/fapi/v1/depth', {
            'symbol': symbol, 'limit': limit
        })
        if 'bids' in data:
            return {
                'bids': [[float(p), float(q)] for p, q in data['bids']],
                'asks': [[float(p), float(q)] for p, q in data['asks']],
                'time': data.get('lastUpdateId', 0),
            }
        return None

    def get_exchange_info(self, symbol=None):
        data = self._get('/fapi/v1/exchangeInfo')
        if 'symbols' in data:
            if symbol:
                for s in data['symbols']:
                    if s['symbol'] == symbol:
                        return s
            return data['symbols']
        return data

    # ========== SIGNED ==========
    def get_account(self):
        return self._get('/fapi/v2/account', signed=True)

    def get_balance(self):
        data = self._get('/fapi/v2/balance', signed=True)
        if isinstance(data, list):
            for b in data:
                if b['asset'] == 'USDT':
                    return {
                        'balance': float(b['balance']),
                        'available': float(b['availableBalance']),
                        'unrealized': float(b.get('crossUnPnl', 0)),
                    }
        return None

    def get_positions(self):
        data = self._get('/fapi/v2/positionRisk', signed=True)
        if isinstance(data, list):
            return [p for p in data if float(p.get('positionAmt', 0)) != 0]
        return []

    def get_open_orders(self, symbol=None):
        params = {}
        if symbol:
            params['symbol'] = symbol
        data = self._get('/fapi/v1/openOrders', params, signed=True)
        if isinstance(data, list):
            return data
        return []

    def set_leverage(self, symbol, leverage):
        return self._post('/fapi/v1/leverage', {
            'symbol': symbol, 'leverage': leverage
        })

    def set_position_mode(self, dual=True):
        mode = 'true' if dual else 'false'
        return self._post('/fapi/v1/positionSide/dual', {'dualSidePosition': mode})

    def market_order(self, symbol, side, quantity, reduce_only=False):
        params = {
            'symbol': symbol,
            'side': side.upper(),
            'type': 'MARKET',
            'quantity': quantity,
        }
        if reduce_only:
            params['reduceOnly'] = 'true'
        return self._post('/fapi/v1/order', params)

    def limit_order(self, symbol, side, quantity, price, time_in_force='GTC'):
        return self._post('/fapi/v1/order', {
            'symbol': symbol,
            'side': side.upper(),
            'type': 'LIMIT',
            'quantity': quantity,
            'price': price,
            'timeInForce': time_in_force,
        })

